mapper.select:
SELECT id, brand, model, interface_type, cores, threads, base_frequency, max_frequency, tdp, integrated_graphics, release_date, create_time, update_time
FROM cpu_info
WHERE id = #{id}

mapper.insert:
INSERT INTO cpu_info (
    brand, model, interface_type, cores, threads, base_frequency, max_frequency, tdp, integrated_graphics, release_date, create_time, update_time
)
VALUES (
           #{brand}, #{model}, #{interfaceType}, #{cores}, #{threads}, #{baseFrequency}, #{maxFrequency}, #{tdp}, #{integratedGraphics}, #{releaseDate}, NOW(), NOW()
       )

mapper.select:
SELECT id, brand, model, memory_size, memory_type, memory_bus_width, base_clock, boost_clock, tdp, interface_type, release_date, create_time, update_time
FROM gpu_info
WHERE id = #{id}

mapper.insert:
INSERT INTO gpu_info (
brand, model, memory_size, memory_type, memory_bus_width, base_clock, boost_clock, tdp, interface_type, release_date, create_time, update_time


)
VALUES (
#{brand}, #{model}, #{memorySize}, #{memoryType}, #{memoryBusWidth}, #{baseClock}, #{boostClock}, #{tdp}, #{interfaceType}, #{releaseDate}, NOW(), NOW()

)

mapper.select:
SELECT id, brand, model, chipset, cpu_interface, memory_slots, max_memory, memory_type, power_phase, sata_ports, m2_slots, release_date, create_time, update_time
FROM motherboard_info
WHERE id = #{id}

mapper.insert:
INSERT INTO motherboard_info (
brand, model, chipset, cpu_interface, memory_slots, max_memory, memory_type, power_phase, sata_ports, m2_slots, release_date, create_time, update_time


)
VALUES (
#{brand}, #{model}, #{chipset}, #{cpuInterface}, #{memorySlots}, #{maxMemory}, #{memoryType}, #{powerPhase}, #{sataPorts}, #{m2Slots}, #{releaseDate}, NOW(), NOW()

)

mapper.update:
UPDATE cpu_info
brand = #{brand}, model = #{model}, interface_type = #{interfaceType}, cores = #{cores}, threads = #{threads}, base_frequency = #{baseFrequency}, max_frequency = #{maxFrequency}, tdp = #{tdp}, integrated_graphics = #{integratedGraphics}, release_date = #{releaseDate}, update_time = NOW()
WHERE id = #{id}
